import { describe, expect, it } from 'vitest';

import {
  admitLiveness,
  admitsLive,
  convSpan,
  liveRoom,
  playRoom,
  recordRoom,
  replayLivenessCertificate,
  ReplayLivenessMaster,
  replaySpan,
  singleRoomBound,
} from '../src/acoustic-replay-liveness';

describe('convSpan (mirrors convSpan / convSpan_ge_left / convSpan_ge_right)', () => {
  it('adds the spans minus the shared onset tap', () => {
    expect(convSpan(6, 5)).toBe(10);
    expect(convSpan(1, 1)).toBe(1);
    expect(convSpan(8, 8)).toBe(15);
  });

  it('never shortens the recording-room tail when the playback room is real', () => {
    // convSpan a b >= a for b >= 1
    for (let a = 1; a <= 6; a++) {
      for (let b = 1; b <= 6; b++) {
        expect(convSpan(a, b)).toBeGreaterThanOrEqual(a);
      }
    }
  });

  it('never shortens the playback-room tail when the recording room is real', () => {
    // convSpan a b >= b for a >= 1
    for (let a = 1; a <= 6; a++) {
      for (let b = 1; b <= 6; b++) {
        expect(convSpan(a, b)).toBeGreaterThanOrEqual(b);
      }
    }
  });

  it('saturates at zero for degenerate empty spans', () => {
    expect(convSpan(0, 0)).toBe(0);
  });
});

describe('admitsLive (mirrors admitsLiveB / AdmitsLive)', () => {
  it('admits a span within the single-room bound', () => {
    expect(admitsLive(singleRoomBound, 5)).toBe(true);
    expect(admitsLive(singleRoomBound, singleRoomBound)).toBe(true);
  });

  it('rejects a span above the single-room bound', () => {
    expect(admitsLive(singleRoomBound, 10)).toBe(false);
    expect(admitsLive(singleRoomBound, singleRoomBound + 1)).toBe(false);
  });
});

describe('promotion check: admitLiveness', () => {
  it('admits a live single-room span (mirrors live_room_admitted)', () => {
    const a = admitLiveness(liveRoom.reflectionSpan);
    expect(a.outcome).toBe('claim_admitted');
    expect(a.limitation).toBe('none');
    expect(a.liveAdmitted).toBe(true);
    expect(a.reflectionSpan).toBe(5);
    expect(a.singleRoomBound).toBe(singleRoomBound);
  });

  it('withholds a composed replay span (mirrors replay_rejected_fixture)', () => {
    const a = admitLiveness(replaySpan);
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('replay_composition_suspected');
    expect(a.liveAdmitted).toBe(false);
    expect(a.reflectionSpan).toBe(10);
  });

  it('admits exactly at the bound and withholds one tap over', () => {
    expect(admitLiveness(singleRoomBound).outcome).toBe('claim_admitted');
    expect(admitLiveness(singleRoomBound + 1).outcome).toBe('claim_withheld');
  });

  it('honors a caller-supplied bound', () => {
    expect(admitLiveness(10, 12).outcome).toBe('claim_admitted');
    expect(admitLiveness(10, 9).outcome).toBe('claim_withheld');
  });

  it('the same source through one room vs two rooms gives opposite verdicts (hard negative)', () => {
    // mirrors same_source_different_liveness
    const live = admitLiveness(liveRoom.reflectionSpan);
    const replayed = admitLiveness(
      convSpan(recordRoom.reflectionSpan, playRoom.reflectionSpan),
    );
    expect(live.outcome).toBe('claim_admitted');
    expect(replayed.outcome).toBe('claim_withheld');
    expect(live.outcome).not.toBe(replayed.outcome);
  });
});

describe('ReplayLivenessMaster (mirrors replay_liveness_master)', () => {
  it('every boundary witness holds', () => {
    expect(ReplayLivenessMaster.liveRoomAdmitted).toBe(true);
    expect(ReplayLivenessMaster.replayRejected).toBe(true);
    expect(ReplayLivenessMaster.replaySpanValue).toBe(true);
    expect(ReplayLivenessMaster.replayLengthensPastLive).toBe(true);
    expect(ReplayLivenessMaster.convSpanNeverShortensLeft).toBe(true);
    expect(ReplayLivenessMaster.convSpanNeverShortensRight).toBe(true);
    expect(ReplayLivenessMaster.certReplayRejected).toBe(true);
    expect(ReplayLivenessMaster.certLivenessAdmitted).toBe(true);
    expect(ReplayLivenessMaster.certHardNegativeSampled).toBe(true);
  });

  it('the certificate records all gates', () => {
    expect(replayLivenessCertificate.reflectionSpanModeled).toBe(true);
    expect(replayLivenessCertificate.singleRoomBounded).toBe(true);
    expect(replayLivenessCertificate.compositionLengthens).toBe(true);
    expect(replayLivenessCertificate.replayRejected).toBe(true);
    expect(replayLivenessCertificate.livenessAdmitted).toBe(true);
    expect(replayLivenessCertificate.hardNegativeSampled).toBe(true);
  });
});
